  CONTROL_PLANE_CLOSEOUT_NEXT_HANDOFF_BOUNDARY_SUITE_POLICY,
  CONTROL_PLANE_CLOSEOUT_NEXT_HANDOFF_BOUNDARY_SUITE_RESULT_FIELDS,
  CONTROL_PLANE_API_SURFACE_BOUNDARY_SUITE_POLICY,
  CONTROL_PLANE_API_SURFACE_BOUNDARY_SUITE_RESULT_FIELDS,
  CONTROL_PLANE_CLAUDE_REVIEW_PERSISTENCE_BOUNDARY_POLICY,
  CONTROL_PLANE_CLAUDE_REVIEW_PERSISTENCE_BOUNDARY_RESULT_FIELDS,
