  CONTROL_PLANE_CLAUDE_REVIEW_SECONDARY_WORKFLOW_PATH_RESULT_FIELDS,
  CONTROL_PLANE_CLAUDE_REVIEW_STATE_TRANSITION_ENFORCEMENT_POLICY,
  CONTROL_PLANE_CLAUDE_REVIEW_STATE_TRANSITION_ENFORCEMENT_RESULT_FIELDS,
  CONTROL_PLANE_CLAUDE_REVIEW_TENANT_BOUNDARY_PRECHECK_POLICY,
  CONTROL_PLANE_CLAUDE_REVIEW_TENANT_BOUNDARY_PRECHECK_RESULT_FIELDS,
  CONTROL_PLANE_CLAUDE_REVIEW_SERVICE_ENTRYPOINT_CONTRACT,
  CONTROL_PLANE_HERMES_VALIDATION_AUDIT_HINT_PRECHECK_POLICY,
  CONTROL_PLANE_HERMES_VALIDATION_AUDIT_HINT_PRECHECK_RESULT_FIELDS,
  CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS,
  CONTROL_PLANE_HERMES_VALIDATION_IDEMPOTENCY_KEY_HANDLING_POLICY,
  CONTROL_PLANE_HERMES_VALIDATION_IDEMPOTENCY_KEY_HANDLING_RESULT_FIELDS,
  CONTROL_PLANE_HERMES_VALIDATION_LOCK_ACQUISITION_RULE_POLICY,
  CONTROL_PLANE_HERMES_VALIDATION_LOCK_ACQUISITION_RULE_RESULT_FIELDS,
  CONTROL_PLANE_HERMES_VALIDATION_ERROR_MAPPING_POLICY,
