    "persist_product_state",
    "mutate_entity_registry",
    "replace_human_approval",
    "bypass_permission_audit",
    "bypass_audit_hint",
    "bypass_human_approval",
    "bypass_claude_review",
    "use_real_client_data",
    "use_real_matter_data",
