export function assertControlPlaneReviewCloseoutFindingRoutingMapPolicy(
  policy = CONTROL_PLANE_REVIEW_CLOSEOUT_FINDING_ROUTING_MAP_POLICY,
) {
  if (!policy || typeof policy !== "object") {
    throw new Error("control-plane Review Closeout Finding Routing Map policy must be an object");
  }
  for (const [field, expected] of [
    ["packId", "CP00-093"],
    ["plannedPackId", "CP00-093"],
    ["requestedPackId", "CP00-092"],
    ["planRef", "docs/closeout-pack-plan/closeout-pack-plan.json"],
    ["source", "requested_locked_queue"],
    ["correctionReason", "requested CP00-092 shifted to CP00-093 by live sequential cursor"],
    ["riskClass", "A"],
    ["unitCount", 1],
    ["sourceMicroPhaseId", "RP00.P09.M05"],
    ["phaseId", "RP00.P09"],
    ["phaseTitle", "Review And Closeout"],
    ["microTitle", "Permission And Audit Binding"],
    ["status", "production_ready"],
    ["title", "Review Closeout Finding Routing Map"],
    ["acceptedInputShape", "control_plane_review_closeout_permission_audit_binding_result_after_CP00-092"],
    ["acceptedEntrypointId", "review_closeout_finding_routing_map"],
    ["rangeDescription", "RP00.P09.M05.S11"],
    ["upstreamPermissionAuditBindingRef", "docs/closeout-packs/cp00-092"],
    ["upstreamPermissionAuditBindingResultRef", "review_closeout.cp00_092.permission_audit_binding_result"],
    ["findingRoutingMapRef", "review_closeout.cp00_093.finding_routing_map"],
    ["ldipPlanningGateRef", "docs/ldip-integration/ldip-overlay-closeout-pack-map.json"],
    ["workingProductBehaviorRef", "assembleControlPlaneReviewCloseoutFindingRoutingMap"],
    ["nextSubphase", "RP00.P09.M06.S01"],
  ]) {
    if (policy[field] !== expected) {
      throw new Error("Review Closeout Finding Routing Map policy " + field + " mismatch");
    }
  }
  if (JSON.stringify(policy.phaseIds) !== JSON.stringify(["RP00.P09"])) {
    throw new Error("Review Closeout Finding Routing Map phase ids mismatch");
  }
  if (JSON.stringify(policy.completedPhaseIds) !== JSON.stringify(["RP00.P08"])) {
    throw new Error("Review Closeout Finding Routing Map completed phase ids mismatch");
  }
  if (JSON.stringify(policy.includedSubphaseIds) !== JSON.stringify(CONTROL_PLANE_REVIEW_CLOSEOUT_FINDING_ROUTING_MAP_SUBPHASE_IDS)) {
    throw new Error("Review Closeout Finding Routing Map included subphase ids must not drift");
  }
  if (
    policy.includedSubphaseIds.length !== 1
    || policy.includedSubphaseIds[0] !== "RP00.P09.M05.S11"
    || policy.rangeDescription !== "RP00.P09.M05.S11"
  ) {
    throw new Error("Review Closeout Finding Routing Map included subphase range mismatch");
  }
  if (JSON.stringify(policy.requiredInputFields) !== JSON.stringify(CONTROL_PLANE_REVIEW_CLOSEOUT_PERMISSION_AUDIT_BINDING_RESULT_FIELDS)) {
    throw new Error("Review Closeout Finding Routing Map requiredInputFields must track CP00-092 result fields");
  }
  requireArrayIncludesAll(
    policy.resultFields,
    CONTROL_PLANE_REVIEW_CLOSEOUT_FINDING_ROUTING_MAP_RESULT_FIELDS,
    "Review Closeout Finding Routing Map policy resultFields",
  );
  if (policy.resultFields.length !== CONTROL_PLANE_REVIEW_CLOSEOUT_FINDING_ROUTING_MAP_RESULT_FIELDS.length) {
    throw new Error("Review Closeout Finding Routing Map policy resultFields must not drift");
  }
  if (
    JSON.stringify(policy.sourceMicroPhaseIds) !== JSON.stringify(["RP00.P09.M05"])
    || !policy.completedSourceMicroPhaseIds.includes("RP00.P09.M05")
    || JSON.stringify(policy.partiallyCompletedSourceMicroPhaseIds) !== JSON.stringify([])
    || JSON.stringify(policy.openSourceMicroPhaseIds) !== JSON.stringify(["RP00.P09.M06"])
  ) {
    throw new Error("Review Closeout Finding Routing Map source map mismatch");
  }
  if (
    !Array.isArray(policy.findingRouteEntries)
    || policy.findingRouteEntries.length !== 4
    || policy.findingRouteEntries[0]?.severity !== "P0"
    || policy.findingRouteEntries[0]?.route !== "block_pack_and_goal_closeout"
    || policy.findingRouteEntries[1]?.severity !== "P1"
    || policy.findingRouteEntries[1]?.route !== "block_pack_and_goal_closeout"
    || policy.findingRouteEntries[2]?.severity !== "P2"
    || policy.findingRouteEntries[2]?.route !== "fix_or_explicit_defer_before_closeout"
    || policy.findingRouteEntries[2]?.p2_defer_allowed !== true
    || policy.findingRouteEntries[3]?.severity !== "P3"
    || policy.severityRoutingContract?.p0_p1_unresolved_allowed !== false
    || policy.severityRoutingContract?.p2_requires_fix_or_defer !== true
    || JSON.stringify(policy.p2DispositionContract?.allowed_dispositions) !== JSON.stringify(["fixed", "explicitly_deferred"])
  ) {
    throw new Error("Review Closeout Finding Routing Map routing contracts mismatch");
  }
  for (const entry of policy.findingRouteEntries) {
    if (
      entry.metadata_only !== true
      || entry.no_real_data !== true
      || entry.disposition_required === undefined
    ) {
      throw new Error("Review Closeout Finding Routing Map entries must stay metadata-only");
    }
  }
  for (const flag of [
    "noRealData",
    "deterministic",
    "hermesValidationBindingRequired",
    "permissionAuditRequired",
    "humanApprovalMarkerRequired",
    "humanApprovalRequiredForSensitiveActions",
    "humanApprovalMarkerIsNotApproval",
    "doesNotExecuteServiceLogic",
    "doesNotCreateRuntimeRoute",
    "doesNotRenderRuntimeUi",
    "doesNotFetchExternalAssets",
    "doesNotEmitRuntimeErrorResponse",
    "doesNotExecuteRuntimeRetry",
    "doesNotExecuteRuntimeRollback",
    "doesNotExecuteRuntimeCompensation",
    "doesNotCreateRuntimeIncident",
    "doesNotWriteObservabilityEvent",
    "doesNotWriteHermesEvidencePacket",
    "doesNotWriteCommandEvidence",
    "doesNotInvokeRuntimeClaudeReview",
    "doesNotWriteReviewQueue",
    "doesNotWriteReviewAssignment",
    "doesNotWriteReviewNotification",
    "doesNotEvaluateRuntimePermission",
    "doesNotCallAuthzEvaluator",
    "doesNotRunPermissionEngine",
    "doesNotApplySecurityTrimming",
    "doesNotAppendAuditLedger",
    "doesNotWriteAuditEvent",
    "doesNotWriteDatabase",
    "doesNotWriteStorage",
    "doesNotPersistProductState",
    "doesNotPersistIdempotencyRecord",
    "doesNotAcquireLock",
    "doesNotCreateRuntimeHumanApproval",
    "doesNotWriteHumanApprovalRecord",
    "doesNotSynthesizeHumanApprovalDecision",
    "doesNotBypassHumanApproval",
    "upstreamPermissionAuditBindingConsumed",
    "riskRegisterConsumed",
    "severityTaxonomyConsumed",
    "goNoGoVerdictFormatConsumed",
    "findingRoutingMapBound",
    "tenantBoundaryRequired",
    "matterTraceRequired",
    "permissionContextVisibleOnly",
    "auditContextVisibleOnly",
  ]) {
    if (policy[flag] !== true) {
      throw new Error("Review Closeout Finding Routing Map policy " + flag + " must be true");
    }
  }
  if (
    policy.writesProductState !== false
    || policy.ldipImplementationAllowed !== false
    || policy.completesSourceMicroPhase !== true
    || policy.phaseCompleted !== false
  ) {
    throw new Error("Review Closeout Finding Routing Map policy closeout flags mismatch");
  }
  return true;
}

