export function assertControlPlaneHermesValidationTenantBoundaryPrecheckPolicy(
  policy = CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_POLICY,
) {
  if (!policy || typeof policy !== "object") {
    throw new Error("control-plane Hermes validation tenant boundary precheck policy must be an object");
  }
  if (policy.subphaseId !== "RP00.P02.M03.S03") {
    throw new Error("Hermes validation tenant boundary precheck policy subphaseId mismatch");
  }
  if (policy.sourceMicroPhaseId !== "RP00.P02.M03") {
    throw new Error("Hermes validation tenant boundary precheck policy sourceMicroPhaseId mismatch");
  }
  if (policy.title !== "Tenant boundary precheck" || policy.microTitle !== "Hermes Validation") {
    throw new Error("Hermes validation tenant boundary precheck policy title mismatch");
  }
  if (policy.status !== "production_ready") {
    throw new Error("Hermes validation tenant boundary precheck policy status must be production_ready");
  }
  if (policy.phaseId !== "RP00.P02" || policy.phaseTitle !== "Service Logic") {
    throw new Error("Hermes validation tenant boundary precheck policy must bind to RP00.P02 Service Logic");
  }
  if (policy.serviceEntrypointContractSubphaseId !== "RP00.P02.M03.S01") {
    throw new Error("Hermes validation tenant boundary precheck policy must reference S01 contract");
  }
  if (policy.hermesValidationRequestNormalizationSubphaseId !== "RP00.P02.M03.S02") {
    throw new Error("Hermes validation tenant boundary precheck policy must reference S02 request normalization");
  }
  if (policy.upstreamTenantBoundaryPrecheckSubphaseId !== "RP00.P02.M00.S03") {
    throw new Error("Hermes validation tenant boundary precheck policy must reference M00 S03");
  }
  if (policy.acceptedInputShape !== "normalized_control_plane_hermes_validation_request") {
    throw new Error("Hermes validation tenant boundary precheck policy accepted input shape mismatch");
  }
  if (policy.acceptedEntrypointId !== "hermes_validation") {
    throw new Error("Hermes validation tenant boundary precheck policy must accept only hermes_validation");
  }
  requireArrayIncludesAll(
    policy.requiredInputFields,
    CONTROL_PLANE_HERMES_VALIDATION_REQUEST_NORMALIZED_FIELDS,
    "Hermes validation tenant boundary precheck policy requiredInputFields",
  );
  if (policy.requiredInputFields.length !== CONTROL_PLANE_HERMES_VALIDATION_REQUEST_NORMALIZED_FIELDS.length) {
    throw new Error("Hermes validation tenant boundary precheck policy requiredInputFields must not drift");
  }
  requireArrayIncludesAll(
    policy.resultFields,
    CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_RESULT_FIELDS,
    "Hermes validation tenant boundary precheck policy resultFields",
  );
  if (policy.resultFields.length !== CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_RESULT_FIELDS.length) {
    throw new Error("Hermes validation tenant boundary precheck policy resultFields must not drift");
  }
  requireArrayIncludesAll(
    policy.validationContextIds,
    CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS,
    "Hermes validation tenant boundary precheck policy validationContextIds",
  );
  if (policy.validationContextIds.length !== CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS.length) {
    throw new Error("Hermes validation tenant boundary precheck policy validationContextIds must not drift");
  }
  if (JSON.stringify(policy.tenantRequirementTraceRefs) !== JSON.stringify(CONTROL_PLANE_TENANT_REQUIREMENT_TRACE_REFS)) {
    throw new Error("Hermes validation tenant boundary precheck policy tenantRequirementTraceRefs mismatch");
  }
  requireArrayIncludesAll(
    policy.acceptanceGateIds,
    CONTROL_PLANE_HERMES_VALIDATION_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds,
    "Hermes validation tenant boundary precheck policy acceptanceGateIds",
  );
  if (policy.acceptanceGateIds.length !== CONTROL_PLANE_HERMES_VALIDATION_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds.length) {
    throw new Error("Hermes validation tenant boundary precheck policy acceptanceGateIds must not drift");
  }
  for (const decision of ["allow_metadata_only", "deny_blocked_claim_required"]) {
    requireArrayIncludesAll(
      policy.decisionValues,
      [decision],
      "Hermes validation tenant boundary precheck policy decisionValues",
    );
  }
  for (const claim of [
    "bypass_tenant_boundary",
    "allow_cross_tenant",
    "execute_service_logic",
    "writes_product_state",
    "mutate_tenant_lifecycle",
    "run_hermes_validation",
    "create_hermes_evidence",
    "bypass_requirement_trace",
    "bypass_human_approval",
    "bypass_hermes_gate",
    "bypass_claude_review",
  ]) {
    requireArrayIncludesAll(
      policy.forbiddenBoundaryClaims,
      [claim],
      "Hermes validation tenant boundary precheck policy forbiddenBoundaryClaims",
    );
  }
  for (const ref of [
    "blocked.synthetic.hermes_validation.tenant_boundary.actor_tenant_mismatch",
    "blocked.synthetic.hermes_validation.tenant_boundary.resource_tenant_mismatch",
    "blocked.synthetic.hermes_validation.tenant_boundary.matter_tenant_missing",
    "blocked.synthetic.hermes_validation.tenant_boundary.matter_tenant_mismatch",
  ]) {
    if (!Object.values(policy.blockedClaimRefs ?? {}).includes(ref)) {
      throw new Error(`Hermes validation tenant boundary precheck policy missing blocked claim ref ${ref}`);
    }
  }
  if (policy.matterTracePrecheckRequired !== true || policy.matterTracePrecheckDeferredTo !== "RP00.P02.M03.S04") {
    throw new Error("Hermes validation tenant boundary precheck policy must defer Matter trace precheck to RP00.P02.M03.S04");
  }
  if (policy.permissionPrecheckRequired !== true || policy.permissionPrecheckDeferredTo !== "RP00.P02.M03.S05") {
    throw new Error("Hermes validation tenant boundary precheck policy must defer permission precheck to RP00.P02.M03.S05");
  }
  if (policy.auditHintPrecheckRequired !== true || policy.auditHintPrecheckDeferredTo !== "RP00.P02.M03.S06") {
    throw new Error("Hermes validation tenant boundary precheck policy must defer audit hint precheck to RP00.P02.M03.S06");
  }
  if (policy.noRealData !== true || policy.writesProductState !== false) {
    throw new Error("Hermes validation tenant boundary precheck policy must be no-real-data and no-write");
  }
  if (policy.deterministic !== true || policy.permissionAuditRequired !== true || policy.requirementTraceRequired !== true) {
    throw new Error("Hermes validation tenant boundary precheck policy must be deterministic, permission-audit aware, and requirement-traced");
  }
  if (policy.doesNotExecuteServiceLogic !== true || policy.doesNotCreateRuntimeRoute !== true) {
    throw new Error("Hermes validation tenant boundary precheck policy must not execute service logic or create routes");
  }
  if (
    policy.doesNotMutateEntityRegistry !== true
    || policy.doesNotReplaceHumanApproval !== true
    || policy.doesNotMutateTenantLifecycle !== true
    || policy.doesNotRunHermesValidation !== true
    || policy.doesNotCreateHermesEvidence !== true
  ) {
    throw new Error("Hermes validation tenant boundary precheck policy must preserve registry, human approval, tenant lifecycle, and Hermes execution boundaries");
  }
  if (policy.completesSourceMicroPhase !== false) {
    throw new Error("Hermes validation tenant boundary precheck policy must not complete RP00.P02.M03");
  }
  if (policy.nextSubphase !== "RP00.P02.M03.S04") {
    throw new Error("Hermes validation tenant boundary precheck policy nextSubphase must be RP00.P02.M03.S04");
  }
  return true;
}

export function assertControlPlaneHermesValidationTenantBoundaryPrecheckResult(result) {
  if (!result || typeof result !== "object" || Array.isArray(result)) {
    throw new Error("control-plane Hermes validation tenant boundary precheck result must be an object");
  }
  for (const field of CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_RESULT_FIELDS) {
    if (!(field in result)) throw new Error(`Hermes validation tenant boundary precheck result missing ${field}`);
  }
  if (result.entrypoint_id !== "hermes_validation") {
    throw new Error("Hermes validation tenant boundary precheck result entrypoint_id mismatch");
  }
  for (const field of ["tenant_id", "actor_id", "actor_tenant_id", "resource_tenant_id", "permission_decision_ref", "audit_event_ref"]) {
    if (typeof result[field] !== "string" || result[field].trim() === "" || result[field] !== result[field].trim()) {
      throw new Error(`Hermes validation tenant boundary precheck result ${field} must be a trimmed nonblank string`);
    }
  }
  if (result.matter_id !== null && (typeof result.matter_id !== "string" || result.matter_id.trim() === "" || result.matter_id !== result.matter_id.trim())) {
    throw new Error("Hermes validation tenant boundary precheck result matter_id must be null or a trimmed nonblank string");
  }
  if (result.matter_tenant_id !== null && (typeof result.matter_tenant_id !== "string" || result.matter_tenant_id.trim() === "" || result.matter_tenant_id !== result.matter_tenant_id.trim())) {
    throw new Error("Hermes validation tenant boundary precheck result matter_tenant_id must be null or a trimmed nonblank string");
  }
  if (result.hermes_validation_request_normalization_ref !== "RP00.P02.M03.S02") {
    throw new Error("Hermes validation tenant boundary precheck result must reference S02 request normalization");
  }
  if (result.m00_request_normalization_ref !== "RP00.P02.M00.S02") {
    throw new Error("Hermes validation tenant boundary precheck result must reference M00 S02 normalization");
  }
  if (result.m00_tenant_boundary_precheck_ref !== "RP00.P02.M00.S03") {
    throw new Error("Hermes validation tenant boundary precheck result must reference M00 S03 precheck");
  }
  if (result.tenant_boundary_precheck_applied !== true || result.tenant_boundary_precheck_subphase_id !== "RP00.P02.M03.S03") {
    throw new Error("Hermes validation tenant boundary precheck result marker mismatch");
  }
  if (!["allow_metadata_only", "deny_blocked_claim_required"].includes(result.tenant_boundary_decision)) {
    throw new Error("Hermes validation tenant boundary precheck result decision mismatch");
  }
  if (typeof result.precheck_passed !== "boolean") {
    throw new Error("Hermes validation tenant boundary precheck result precheck_passed must be boolean");
  }
  if (result.precheck_passed !== (result.tenant_boundary_decision === "allow_metadata_only")) {
    throw new Error("Hermes validation tenant boundary precheck result pass flag must match decision");
  }
  if (!Array.isArray(result.blocked_claim_refs)) {
    throw new Error("Hermes validation tenant boundary precheck result blocked_claim_refs must be an array");
  }
  for (const value of result.blocked_claim_refs) {
    if (typeof value !== "string" || value.trim() === "" || value !== value.trim()) {
      throw new Error("Hermes validation tenant boundary precheck result blocked_claim_refs values must be trimmed nonblank strings");
    }
  }
  if (result.precheck_passed === false && result.blocked_claim_refs.length === 0) {
    throw new Error("Hermes validation tenant boundary precheck denied result must include a blocked claim ref");
  }
  if (result.precheck_passed === true && result.blocked_claim_refs.length !== 0) {
    throw new Error("Hermes validation tenant boundary precheck allowed result must not include blocked claim refs");
  }
  if (result.tenant_id !== result.actor_tenant_id && result.precheck_passed !== false) {
    throw new Error("Hermes validation actor tenant mismatch must fail closed");
  }
  const blockedRefs = CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_POLICY.blockedClaimRefs;
  if (
    result.tenant_id !== result.actor_tenant_id
    && !result.blocked_claim_refs.includes(blockedRefs.actorTenantMismatch)
  ) {
    throw new Error("Hermes validation actor tenant mismatch must include actor blocked claim ref");
  }
  if (result.tenant_id !== result.resource_tenant_id && result.precheck_passed !== false) {
    throw new Error("Hermes validation resource tenant mismatch must fail closed");
  }
  if (
    result.tenant_id !== result.resource_tenant_id
    && !result.blocked_claim_refs.includes(blockedRefs.resourceTenantMismatch)
  ) {
    throw new Error("Hermes validation resource tenant mismatch must include resource blocked claim ref");
  }
  if (result.matter_id !== null && result.matter_tenant_id === null && result.precheck_passed !== false) {
    throw new Error("Hermes validation missing matter tenant must fail closed");
  }
  if (
    result.matter_id !== null
    && result.matter_tenant_id === null
    && !result.blocked_claim_refs.includes(blockedRefs.matterTenantMissing)
  ) {
    throw new Error("Hermes validation missing matter tenant must include missing Matter tenant blocked claim ref");
  }
  if (result.matter_tenant_id !== null && result.tenant_id !== result.matter_tenant_id && result.precheck_passed !== false) {
    throw new Error("Hermes validation matter tenant mismatch must fail closed");
  }
  if (
    result.matter_tenant_id !== null
    && result.tenant_id !== result.matter_tenant_id
    && !result.blocked_claim_refs.includes(blockedRefs.matterTenantMismatch)
  ) {
    throw new Error("Hermes validation matter tenant mismatch must include Matter tenant mismatch blocked claim ref");
  }
  if (JSON.stringify(result.validation_context_ids) !== JSON.stringify(CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS)) {
    throw new Error("Hermes validation tenant boundary precheck result validation_context_ids mismatch");
  }
  if (JSON.stringify(result.tenant_requirement_trace_refs) !== JSON.stringify(CONTROL_PLANE_TENANT_REQUIREMENT_TRACE_REFS)) {
    throw new Error("Hermes validation tenant boundary precheck result tenant_requirement_trace_refs mismatch");
  }
  if (JSON.stringify(result.acceptance_gate_ids) !== JSON.stringify(CONTROL_PLANE_HERMES_VALIDATION_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds)) {
    throw new Error("Hermes validation tenant boundary precheck result acceptance_gate_ids mismatch");
  }
  if (result.requirement_trace_required !== true) {
    throw new Error("Hermes validation tenant boundary precheck result must keep requirement trace required");
  }
  if (
    result.tenant_lifecycle_mutation_permitted !== false
    || result.hermes_validation_execution_permitted !== false
    || result.hermes_evidence_creation_permitted !== false
    || result.service_logic_execution_permitted !== false
    || result.runtime_route_created !== false
  ) {
    throw new Error("Hermes validation tenant boundary precheck result must not permit tenant mutation, Hermes execution/evidence, service execution, or runtime route creation");
  }
  if (result.no_real_data !== true || result.writes_product_state !== false) {
    throw new Error("Hermes validation tenant boundary precheck result must be no-real-data and no-write");
  }
  if (result.next_subphase !== "RP00.P02.M03.S04") {
    throw new Error("Hermes validation tenant boundary precheck result next_subphase must be RP00.P02.M03.S04");
  }
  return true;
}

export function assertControlPlaneHermesValidationMatterTracePrecheckPolicy(
  policy = CONTROL_PLANE_HERMES_VALIDATION_MATTER_TRACE_PRECHECK_POLICY,
) {
  if (!policy || typeof policy !== "object") {
    throw new Error("control-plane Hermes validation Matter trace precheck policy must be an object");
  }
  if (policy.subphaseId !== "RP00.P02.M03.S04") {
    throw new Error("Hermes validation Matter trace precheck policy subphaseId mismatch");
  }
  if (policy.sourceMicroPhaseId !== "RP00.P02.M03") {
    throw new Error("Hermes validation Matter trace precheck policy sourceMicroPhaseId mismatch");
  }
  if (policy.title !== "Matter trace precheck" || policy.microTitle !== "Hermes Validation") {
    throw new Error("Hermes validation Matter trace precheck policy title mismatch");
  }
  if (policy.status !== "production_ready") {
    throw new Error("Hermes validation Matter trace precheck policy status must be production_ready");
  }
  if (policy.phaseId !== "RP00.P02" || policy.phaseTitle !== "Service Logic") {
    throw new Error("Hermes validation Matter trace precheck policy must bind to RP00.P02 Service Logic");
  }
  if (policy.serviceEntrypointContractSubphaseId !== "RP00.P02.M03.S01") {
    throw new Error("Hermes validation Matter trace precheck policy must reference S01 contract");
  }
  if (policy.hermesValidationRequestNormalizationSubphaseId !== "RP00.P02.M03.S02") {
    throw new Error("Hermes validation Matter trace precheck policy must reference S02 request normalization");
  }
  if (policy.tenantBoundaryPrecheckSubphaseId !== "RP00.P02.M03.S03") {
    throw new Error("Hermes validation Matter trace precheck policy must reference S03 tenant boundary precheck");
  }
  if (policy.matterFirstTraceRulesSubphaseId !== "RP00.P00.M04.S01") {
    throw new Error("Hermes validation Matter trace precheck policy must reference Matter-first trace rules");
  }
  if (policy.acceptedInputShape !== "control_plane_hermes_validation_tenant_boundary_precheck_result_after_RP00.P02.M03.S03") {
    throw new Error("Hermes validation Matter trace precheck policy accepted input shape mismatch");
  }
  if (policy.acceptedEntrypointId !== "hermes_validation") {
    throw new Error("Hermes validation Matter trace precheck policy must accept only hermes_validation");
  }
  requireArrayIncludesAll(
    policy.requiredInputFields,
    CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_RESULT_FIELDS,
    "Hermes validation Matter trace precheck policy requiredInputFields",
  );
  if (policy.requiredInputFields.length !== CONTROL_PLANE_HERMES_VALIDATION_TENANT_BOUNDARY_PRECHECK_RESULT_FIELDS.length) {
    throw new Error("Hermes validation Matter trace precheck policy requiredInputFields must not drift");
  }
  requireArrayIncludesAll(
    policy.resultFields,
    CONTROL_PLANE_HERMES_VALIDATION_MATTER_TRACE_PRECHECK_RESULT_FIELDS,
    "Hermes validation Matter trace precheck policy resultFields",
  );
  if (policy.resultFields.length !== CONTROL_PLANE_HERMES_VALIDATION_MATTER_TRACE_PRECHECK_RESULT_FIELDS.length) {
    throw new Error("Hermes validation Matter trace precheck policy resultFields must not drift");
  }
  requireArrayIncludesAll(
    policy.validationContextIds,
    CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS,
    "Hermes validation Matter trace precheck policy validationContextIds",
  );
  if (policy.validationContextIds.length !== CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS.length) {
    throw new Error("Hermes validation Matter trace precheck policy validationContextIds must not drift");
  }
  if (JSON.stringify(policy.tenantRequirementTraceRefs) !== JSON.stringify(CONTROL_PLANE_TENANT_REQUIREMENT_TRACE_REFS)) {
    throw new Error("Hermes validation Matter trace precheck policy tenantRequirementTraceRefs mismatch");
  }
  requireArrayIncludesAll(
    policy.acceptanceGateIds,
    CONTROL_PLANE_HERMES_VALIDATION_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds,
    "Hermes validation Matter trace precheck policy acceptanceGateIds",
  );
  for (const decision of ["allow_metadata_only", "deny_blocked_claim_required"]) {
    requireArrayIncludesAll(policy.decisionValues, [decision], "Hermes validation Matter trace precheck policy decisionValues");
  }
  for (const scope of ["firm_level_control_plane_metadata", "matter_scoped_control_plane_metadata"]) {
    requireArrayIncludesAll(policy.matterTraceScopes, [scope], "Hermes validation Matter trace precheck policy matterTraceScopes");
  }
  for (const claim of [
    "touches_client_data",
    "touches_matter_data",
    "touches_document_data",
    "touches_document_version_data",
    "touches_billing_or_finance_data",
    "touches_tenant_lifecycle_data",
    "touches_command_evidence",
    "touches_hermes_gate_evidence",
    "touches_requirement_trace",
    "touches_client_facing_ai_output",
    "touches_external_share_or_portal_output",
  ]) {
    requireArrayIncludesAll(policy.matterRequiredClaims, [claim], "Hermes validation Matter trace precheck policy matterRequiredClaims");
  }
  for (const claim of [
    "bypass_matter_trace",
    "execute_service_logic",
    "writes_product_state",
    "mutate_tenant_lifecycle",
    "run_hermes_validation",
    "create_hermes_evidence",
    "bypass_requirement_trace",
    "bypass_human_approval",
    "bypass_hermes_gate",
    "bypass_claude_review",
  ]) {
    requireArrayIncludesAll(policy.forbiddenMatterTraceClaims, [claim], "Hermes validation Matter trace precheck policy forbiddenMatterTraceClaims");
  }
  for (const reason of [
    "missing_tenant_boundary_precheck_result",
    "tenant_boundary_precheck_not_RP00.P02.M03.S03",
    "tenant_boundary_precheck_denied",
    "non_hermes_validation_entrypoint",
    "matter_required_but_missing",
    "matter_tenant_missing",
    "matter_tenant_mismatch",
    "matter_trace_bypass_claim",
    "unknown_truthy_matter_trace_claim",
    "tenant_lifecycle_mutation_claim",
    "hermes_execution_or_evidence_claim",
    "requirement_trace_bypass_claim",
    "review_gate_bypass_claim",
  ]) {
    requireArrayIncludesAll(policy.failClosedOn, [reason], "Hermes validation Matter trace precheck policy failClosedOn");
  }
  for (const ref of [
    "blocked.synthetic.hermes_validation.matter_trace.matter_required_missing",
    "blocked.synthetic.hermes_validation.matter_trace.matter_tenant_missing",
    "blocked.synthetic.hermes_validation.matter_trace.matter_tenant_mismatch",
  ]) {
    if (!Object.values(policy.blockedClaimRefs ?? {}).includes(ref)) {
      throw new Error(`Hermes validation Matter trace precheck policy missing blocked claim ref ${ref}`);
    }
  }
  if (policy.permissionPrecheckRequired !== true || policy.permissionPrecheckDeferredTo !== "RP00.P02.M03.S05") {
    throw new Error("Hermes validation Matter trace precheck policy must defer permission precheck to RP00.P02.M03.S05");
  }
  if (policy.auditHintPrecheckRequired !== true || policy.auditHintPrecheckDeferredTo !== "RP00.P02.M03.S06") {
    throw new Error("Hermes validation Matter trace precheck policy must defer audit hint precheck to RP00.P02.M03.S06");
  }
  if (policy.noRealData !== true || policy.writesProductState !== false) {
    throw new Error("Hermes validation Matter trace precheck policy must be no-real-data and no-write");
  }
  if (policy.deterministic !== true || policy.permissionAuditRequired !== true || policy.requirementTraceRequired !== true) {
    throw new Error("Hermes validation Matter trace precheck policy must be deterministic, permission-audit aware, and requirement-traced");
  }
  if (policy.doesNotExecuteServiceLogic !== true || policy.doesNotCreateRuntimeRoute !== true) {
    throw new Error("Hermes validation Matter trace precheck policy must not execute service logic or create routes");
  }
  if (
    policy.doesNotMutateEntityRegistry !== true
    || policy.doesNotReplaceHumanApproval !== true
    || policy.doesNotMutateTenantLifecycle !== true
    || policy.doesNotRunHermesValidation !== true
    || policy.doesNotCreateHermesEvidence !== true
  ) {
    throw new Error("Hermes validation Matter trace precheck policy must preserve registry, human approval, tenant lifecycle, and Hermes execution boundaries");
  }
  if (policy.completesSourceMicroPhase !== false) {
    throw new Error("Hermes validation Matter trace precheck policy must not complete RP00.P02.M03");
  }
  if (policy.nextSubphase !== "RP00.P02.M03.S05") {
    throw new Error("Hermes validation Matter trace precheck policy nextSubphase must be RP00.P02.M03.S05");
  }
  return true;
}

export function assertControlPlaneHermesValidationMatterTracePrecheckResult(result) {
  if (!result || typeof result !== "object" || Array.isArray(result)) {
    throw new Error("control-plane Hermes validation Matter trace precheck result must be an object");
  }
  for (const field of CONTROL_PLANE_HERMES_VALIDATION_MATTER_TRACE_PRECHECK_RESULT_FIELDS) {
    if (!(field in result)) throw new Error(`Hermes validation Matter trace precheck result missing ${field}`);
  }
  if (result.entrypoint_id !== "hermes_validation") {
    throw new Error("Hermes validation Matter trace precheck result entrypoint_id mismatch");
  }
  for (const field of ["tenant_id", "actor_id", "actor_tenant_id", "resource_tenant_id", "permission_decision_ref", "audit_event_ref"]) {
    if (typeof result[field] !== "string" || result[field].trim() === "" || result[field] !== result[field].trim()) {
      throw new Error(`Hermes validation Matter trace precheck result ${field} must be a trimmed nonblank string`);
    }
  }
  if (result.matter_id !== null && (typeof result.matter_id !== "string" || result.matter_id.trim() === "" || result.matter_id !== result.matter_id.trim())) {
    throw new Error("Hermes validation Matter trace precheck result matter_id must be null or a trimmed nonblank string");
  }
  if (result.matter_tenant_id !== null && (typeof result.matter_tenant_id !== "string" || result.matter_tenant_id.trim() === "" || result.matter_tenant_id !== result.matter_tenant_id.trim())) {
    throw new Error("Hermes validation Matter trace precheck result matter_tenant_id must be null or a trimmed nonblank string");
  }
  if (result.hermes_validation_request_normalization_ref !== "RP00.P02.M03.S02") {
    throw new Error("Hermes validation Matter trace precheck result must reference S02 request normalization");
  }
  if (result.tenant_boundary_precheck_ref !== "RP00.P02.M03.S03") {
    throw new Error("Hermes validation Matter trace precheck result must reference S03 tenant boundary precheck");
  }
  if (result.m00_request_normalization_ref !== "RP00.P02.M00.S02" || result.m00_tenant_boundary_precheck_ref !== "RP00.P02.M00.S03") {
    throw new Error("Hermes validation Matter trace precheck result must preserve M00 refs");
  }
  if (result.matter_trace_precheck_applied !== true || result.matter_trace_precheck_subphase_id !== "RP00.P02.M03.S04") {
    throw new Error("Hermes validation Matter trace precheck result marker mismatch");
  }
  if (!["allow_metadata_only", "deny_blocked_claim_required"].includes(result.matter_trace_decision)) {
    throw new Error("Hermes validation Matter trace precheck result decision mismatch");
  }
  if (typeof result.matter_trace_required !== "boolean" || typeof result.matter_trace_satisfied !== "boolean") {
    throw new Error("Hermes validation Matter trace precheck result booleans mismatch");
  }
  if (result.matter_trace_satisfied !== (result.matter_trace_decision === "allow_metadata_only")) {
    throw new Error("Hermes validation Matter trace precheck result satisfied flag must match decision");
  }
  if (!["firm_level_control_plane_metadata", "matter_scoped_control_plane_metadata"].includes(result.matter_trace_scope)) {
    throw new Error("Hermes validation Matter trace precheck result scope mismatch");
  }
  if (!Array.isArray(result.blocked_claim_refs)) {
    throw new Error("Hermes validation Matter trace precheck result blocked_claim_refs must be an array");
  }
  for (const value of result.blocked_claim_refs) {
    if (typeof value !== "string" || value.trim() === "" || value !== value.trim()) {
      throw new Error("Hermes validation Matter trace precheck result blocked_claim_refs values must be trimmed nonblank strings");
    }
  }
  if (result.matter_trace_satisfied === false && result.blocked_claim_refs.length === 0) {
    throw new Error("Hermes validation Matter trace denied result must include a blocked claim ref");
  }
  if (result.matter_trace_satisfied === true && result.blocked_claim_refs.length !== 0) {
    throw new Error("Hermes validation Matter trace allowed result must not include blocked claim refs");
  }
  const blockedRefs = CONTROL_PLANE_HERMES_VALIDATION_MATTER_TRACE_PRECHECK_POLICY.blockedClaimRefs;
  if (result.matter_id !== null && result.matter_trace_required !== true) {
    throw new Error("Hermes validation Matter trace result with matter_id must require Matter trace");
  }
  if (result.matter_trace_required === true && result.matter_id === null && result.matter_trace_satisfied !== false) {
    throw new Error("Hermes validation Matter trace required without matter_id must fail closed");
  }
  if (
    result.matter_trace_required === true
    && result.matter_id === null
    && !result.blocked_claim_refs.includes(blockedRefs.matterRequiredMissing)
  ) {
    throw new Error("Hermes validation Matter trace required without matter_id must include matter-required blocked claim ref");
  }
  if (result.matter_id !== null && result.matter_tenant_id === null && result.matter_trace_satisfied !== false) {
    throw new Error("Hermes validation Matter trace missing matter tenant must fail closed");
  }
  if (
    result.matter_id !== null
    && result.matter_tenant_id === null
    && !result.blocked_claim_refs.includes(blockedRefs.matterTenantMissing)
  ) {
    throw new Error("Hermes validation Matter trace missing matter tenant must include missing Matter tenant blocked claim ref");
  }
  if (result.matter_tenant_id !== null && result.tenant_id !== result.matter_tenant_id && result.matter_trace_satisfied !== false) {
    throw new Error("Hermes validation Matter trace matter tenant mismatch must fail closed");
  }
  if (
    result.matter_tenant_id !== null
    && result.tenant_id !== result.matter_tenant_id
    && !result.blocked_claim_refs.includes(blockedRefs.matterTenantMismatch)
  ) {
    throw new Error("Hermes validation Matter trace matter tenant mismatch must include Matter tenant mismatch blocked claim ref");
  }
  if (result.matter_trace_required === false && result.matter_trace_scope !== "firm_level_control_plane_metadata") {
    throw new Error("Hermes validation Matter trace firm-level scope mismatch");
  }
  if (result.matter_trace_required === true && result.matter_trace_scope !== "matter_scoped_control_plane_metadata") {
    throw new Error("Hermes validation Matter trace matter-scoped scope mismatch");
  }
  if (JSON.stringify(result.validation_context_ids) !== JSON.stringify(CONTROL_PLANE_HERMES_VALIDATION_CONTEXT_IDS)) {
    throw new Error("Hermes validation Matter trace precheck result validation_context_ids mismatch");
  }
  if (JSON.stringify(result.tenant_requirement_trace_refs) !== JSON.stringify(CONTROL_PLANE_TENANT_REQUIREMENT_TRACE_REFS)) {
    throw new Error("Hermes validation Matter trace precheck result tenant_requirement_trace_refs mismatch");
  }
  if (JSON.stringify(result.acceptance_gate_ids) !== JSON.stringify(CONTROL_PLANE_HERMES_VALIDATION_SERVICE_ENTRYPOINT_CONTRACT.acceptanceGateIds)) {
    throw new Error("Hermes validation Matter trace precheck result acceptance_gate_ids mismatch");
  }
  if (result.requirement_trace_required !== true) {
    throw new Error("Hermes validation Matter trace precheck result must keep requirement trace required");
  }
  if (
    result.tenant_lifecycle_mutation_permitted !== false
    || result.hermes_validation_execution_permitted !== false
    || result.hermes_evidence_creation_permitted !== false
    || result.service_logic_execution_permitted !== false
    || result.runtime_route_created !== false
  ) {
    throw new Error("Hermes validation Matter trace precheck result must not permit tenant mutation, Hermes execution/evidence, service execution, or runtime route creation");
  }
  if (result.no_real_data !== true || result.writes_product_state !== false) {
    throw new Error("Hermes validation Matter trace precheck result must be no-real-data and no-write");
  }
  if (result.next_subphase !== "RP00.P02.M03.S05") {
    throw new Error("Hermes validation Matter trace precheck result next_subphase must be RP00.P02.M03.S05");
  }
  return true;
}

