    "create_runtime_route",
    "writes_product_state",
    "mutate_tenant_lifecycle",
    "run_hermes_validation",
    "create_hermes_evidence",
    "append_audit_ledger",
    "write_audit_event",
    "evaluate_runtime_permission",
    "run_permission_engine",
