    "acquire_runtime_lock",
    "lock_resource",
    "lock_matter",
    "persist_lock_record",
    "write_lock_store",
    "create_ui",
    "render_ui",
    "bypass_permission_audit",
    "bypass_audit_hint",
    "bypass_primary_happy_path",
    "bypass_secondary_workflow_path",
    "bypass_state_transition",
    "bypass_idempotency_key",
    "bypass_lock_acquisition_rule",
    "bypass_requirement_trace",
