function assertSyntheticIdempotencyKey(value, label) {
  if (typeof value !== "string" || value.trim() === "" || value !== value.trim()) {
    throw new Error(`${label} must be a trimmed nonblank string`);
  }
  if (!value.startsWith("idem.synthetic.") || !/^idem\.synthetic\.[a-z0-9._:-]{1,113}$/.test(value) || value.length > 128) {
    throw new Error(`${label} must be a safe synthetic idempotency key`);
  }
}

